import{jsx as _jsx}from"react/jsx-runtime";import*as React from"react";import{usePlatform}from"../../hooks/usePlatform.js";import{Caption}from"../Typography/Caption/Caption.js";import{Footnote}from"../Typography/Footnote/Footnote.js";import{Text}from"../Typography/Text/Text.js";import{Title}from"../Typography/Title/Title.js";import styles from"./Alert.module.css";const AlertHeader=t=>{var e=usePlatform();return _jsx(Title,"ios"!==e?{className:styles.header,weight:"2",level:"2",...t}:{className:styles.header,weight:"1",level:"3",...t})},AlertText=t=>{switch(usePlatform()){case"vkcom":return _jsx(Footnote,{className:styles.text,...t});case"ios":return _jsx(Caption,{className:styles.text,...t});default:return _jsx(Text,{Component:"span",className:styles.text,weight:"3",...t})}};export{AlertHeader,AlertText};